def analyze_series(series_dict):
    best_name = None
    best_total = 0
    for name, values in series_dict.items():
        total = sum(values)
        print(f"{name}: total = {total}")
        if total > best_total:
            best_total = total
            best_name = name
    print(f"Legend highlight: {best_name} (highest total: {best_total})")

data = {'Product A': [100, 200, 150, 300], 'Product B': [180, 160, 210, 250], 'Product C': [90, 140, 180, 220]}
analyze_series(data)

def recommend_chart(x_type, y_type, purpose):
    if purpose == 'comparison' and x_type == 'categorical':
        chart = 'Bar Chart'
    elif purpose == 'distribution' and x_type == 'continuous':
        chart = 'Histogram'
    elif purpose == 'relationship' and x_type == 'continuous' and y_type == 'continuous':
        chart = 'Scatter Plot'
    elif purpose == 'composition' and x_type == 'categorical':
        chart = 'Pie Chart'
    else:
        chart = 'Box Plot'
    print(f"Data: {x_type} vs {y_type} | Purpose: {purpose} -> {chart}")

recommend_chart('categorical', 'continuous', 'comparison')
recommend_chart('continuous', 'continuous', 'relationship')
recommend_chart('continuous', 'continuous', 'distribution')
recommend_chart('categorical', 'continuous', 'composition')
recommend_chart('categorical', 'categorical', 'distribution')

def pie_chart_data(labels, values):
    total = sum(values)
    for label, val in zip(labels, values):
        pct = val / total * 100
        angle = val / total * 360
        print(f"  {label}: {val} ({pct:.1f}%, {angle:.1f}deg)")
    count = len(labels)
    print(f"Slices: {count}")
    if count <= 5:
        print("Recommendation: Pie chart")
    else:
        print(f"Recommendation: Use bar chart instead ({count} categories is too many for pie)")

pie_chart_data(['Chrome', 'Firefox', 'Safari', 'Edge', 'Opera', 'Other'], [65, 10, 9, 8, 3, 5])

def generate_title(metric, current, previous, period):
    if previous == 0:
        print(f"{metric} is ${current:,} in {period} (no prior data)")
        return
    pct = (current - previous) / previous * 100
    if pct > 0:
        print(f"{metric} grew {pct:.0f}% to ${current:,} in {period}")
    elif pct < 0:
        print(f"{metric} declined {abs(pct):.0f}% to ${current:,} in {period}")
    else:
        print(f"{metric} remained flat at ${current:,} in {period}")

generate_title('Revenue', 1250000, 890000, 'Q3 2025')
generate_title('Expenses', 450000, 520000, 'Q3 2025')
generate_title('Profit', 300000, 300000, 'Q3 2025')
